-- Seed del catálogo de deducciones autonómicas.
--
-- Carga las deducciones del manual "Renta 2025 — Parte 2" de la AEAT.
-- Origen: archivos supabase/seeds/renta/deductions/<CCAA>.json (extraídos del
-- PDF oficial). Para regenerar esta migración tras editar los JSON, ejecuta:
--
--     node scripts/build-renta-seed.mjs
--
-- NOTAS:
-- - Navarra y País Vasco NO están: tienen régimen foral propio (no aparecen
--   en el manual de la AEAT).
-- - Para deducciones con fórmulas de cálculo complejas (% sobre cuota,
--   prorrateos, etc.) solo se encoda el gate básico de elegibilidad; el
--   importe lo calcula el asesor revisando la submission.
-- - Total deducciones cargadas: 349 en 15 CCAA.

-- Idempotencia: TRUNCATE garantiza que deducciones eliminadas del manual
-- desaparezcan de la BD al re-ejecutar el seed.
TRUNCATE TABLE renta.deductions;

INSERT INTO renta.deductions (
  id, ccaa_code, title, summary, legal_reference,
  eligibility_rule, extra_fields, display_order, is_active
)
SELECT
  (row->>'id')::text,
  (row->>'ccaa_code')::text,
  (row->>'title')::text,
  (row->>'summary')::text,
  (row->>'legal_reference')::text,
  COALESCE(row->'eligibility_rule', '{"all_of":[]}'::jsonb),
  COALESCE(row->'extra_fields', '[]'::jsonb),
  COALESCE((row->>'display_order')::int, 0),
  COALESCE((row->>'is_active')::boolean, true)
FROM jsonb_array_elements('[{"id":"and-vivienda-protegida-jovenes","ccaa_code":"ES-AN","title":"Por inversión en vivienda habitual que tenga la consideración de protegida y por las personas jóvenes","summary":"6% de las cantidades satisfechas por adquisición o rehabilitación de vivienda habitual calificada como protegida en Andalucía o adquirida por menores de 35 años. Base máxima 9.040 €. Suma de bases imponibles ≤ 25.000 € (individual) / 30.000 € (conjunta).","legal_reference":"Arts. 9 y 2 y disposición adicional primera Ley 5/2021, de 20 de octubre, de Tributos Cedidos de la Comunidad Autónoma de Andalucía","eligibility_rule":{"all_of":[{"op":"eq","path":"ccaa","value":"ES-AN"},{"op":"eq","path":"housing.type","value":"propiedad"},{"op":"eq","path":"housing.is_habitual","value":true},{"any_of":[{"all_of":[{"op":"eq","path":"declaration_mode","value":"individual"},{"op":"lte","path":"income_base","value":25000}]},{"all_of":[{"op":"eq","path":"declaration_mode","value":"conjunta"},{"op":"lte","path":"income_base","value":30000}]}]}]},"extra_fields":[{"key":"acquisition_or_rehab_amount_eur","label":"Cantidades satisfechas en el ejercicio por adquisición o rehabilitación (€)","kind":"number","required":true,"min":0},{"key":"housing_type","label":"Supuesto que da derecho","kind":"select","required":true,"options":[{"value":"protegida","label":"Vivienda con calificación de protegida"},{"value":"joven_menor_35","label":"Adquirente menor de 35 años"},{"value":"ambos","label":"Vivienda protegida y adquirente menor de 35 años"}]},{"key":"acquisition_date","label":"Fecha de adquisición o inicio de rehabilitación","kind":"date","required":false},{"key":"external_financing","label":"¿Existe financiación ajena (préstamo hipotecario)?","kind":"boolean","required":false}],"display_order":10,"is_active":true},{"id":"and-alquiler-vivienda-habitual","ccaa_code":"ES-AN","title":"Por cantidades invertidas en el alquiler de la vivienda habitual","summary":"15% de las cantidades pagadas por alquiler de vivienda habitual. Máximo 1.200 €/año (1.500 € si discapacidad). Requiere ser menor de 35 años, mayor de 65 o víctima de violencia doméstica/terrorismo. Suma de bases ≤ 25.000 € (individual) / 30.000 € (conjunta).","legal_reference":"Arts. 10 y 2 y disposición adicional primera Ley 5/2021, de 20 de octubre, de Tributos Cedidos de la Comunidad Autónoma de Andalucía","eligibility_rule":{"all_of":[{"op":"eq","path":"ccaa","value":"ES-AN"},{"op":"eq","path":"housing.type","value":"alquiler"},{"any_of":[{"all_of":[{"op":"eq","path":"declaration_mode","value":"individual"},{"op":"lte","path":"income_base","value":25000}]},{"all_of":[{"op":"eq","path":"declaration_mode","value":"conjunta"},{"op":"lte","path":"income_base","value":30000}]}]}]},"extra_fields":[{"key":"annual_rent_eur","label":"Renta anual pagada (€)","kind":"number","required":true,"min":0},{"key":"tenant_circumstance","label":"Circunstancia que da derecho","kind":"select","required":true,"options":[{"value":"menor_35","label":"Menor de 35 años a fecha de devengo"},{"value":"mayor_65","label":"Mayor de 65 años a fecha de devengo"},{"value":"victima_violencia_domestica","label":"Víctima de violencia doméstica"},{"value":"victima_terrorismo","label":"Víctima del terrorismo o persona afectada"}]},{"key":"is_disabled","label":"¿Persona con discapacidad (≥33% o ≥65% si pre-2022)?","kind":"boolean","required":false},{"key":"landlord_nif","label":"NIF del arrendador","kind":"text","required":true},{"key":"is_contract_holder","label":"Confirmo que soy titular del contrato de arrendamiento","kind":"boolean","required":true}],"display_order":20,"is_active":true},{"id":"and-nacimiento-adopcion-acogimiento","ccaa_code":"ES-AN","title":"Por nacimiento, adopción de hijos o acogimiento familiar de menores","summary":"200 € por cada hijo nacido, adoptado o menor en acogimiento (400 € si residencia en municipio con problemas de despoblación, <3.000 habitantes). Incremento de 200 €/hijo en partos/adopciones múltiples. En acogimiento exige no recibir ayudas de la Junta y convivencia ≥90 días.","legal_reference":"Art. 11 Ley 5/2021, de 20 de octubre, de Tributos Cedidos de la Comunidad Autónoma de Andalucía","eligibility_rule":{"all_of":[{"op":"eq","path":"ccaa","value":"ES-AN"},{"op":"gte","path":"kids.length","value":1}]},"extra_fields":[{"key":"kids_born_or_adopted","label":"Hijos nacidos/adoptados o menores acogidos en el ejercicio (uno por línea: nombre y fecha)","kind":"textarea","required":true},{"key":"trigger_type","label":"Supuesto que da derecho","kind":"select","required":true,"options":[{"value":"nacimiento","label":"Nacimiento"},{"value":"adopcion","label":"Adopción"},{"value":"acogimiento_urgencia","label":"Acogimiento familiar de urgencia"},{"value":"acogimiento_temporal","label":"Acogimiento familiar temporal"},{"value":"acogimiento_permanente","label":"Acogimiento familiar permanente"},{"value":"guarda_preadoptiva","label":"Delegación de guarda con fines de convivencia preadoptiva"}]},{"key":"multiple_birth_or_adoption","label":"¿Parto, adopción o acogimiento múltiple?","kind":"boolean","required":false},{"key":"small_municipality","label":"¿Residencia en municipio con problemas de despoblación (<3.000 hab.)?","kind":"boolean","required":false},{"key":"no_aids_received","label":"(Acogimiento) Confirmo no haber recibido ayudas de la Junta vinculadas al acogimiento","kind":"boolean","required":false}],"display_order":30,"is_active":true},{"id":"and-adopcion-internacional","ccaa_code":"ES-AN","title":"Por adopción de hijos en el ámbito internacional","summary":"600 € por cada hijo adoptado en el período impositivo en el que se inscribe la adopción en el Registro Civil, siempre que sea de carácter internacional. Suma de bases ≤ 80.000 € (individual) / 100.000 € (conjunta). Incompatible con la deducción por nacimiento respecto del mismo hijo.","legal_reference":"Art. 12 Ley 5/2021, de 20 de octubre, de Tributos Cedidos de la Comunidad Autónoma de Andalucía","eligibility_rule":{"all_of":[{"op":"eq","path":"ccaa","value":"ES-AN"},{"op":"gte","path":"kids.length","value":1},{"any_of":[{"all_of":[{"op":"eq","path":"declaration_mode","value":"individual"},{"op":"lte","path":"income_base","value":80000}]},{"all_of":[{"op":"eq","path":"declaration_mode","value":"conjunta"},{"op":"lte","path":"income_base","value":100000}]}]}]},"extra_fields":[{"key":"international_adoption_kids","label":"Hijos adoptados internacionalmente (nombre y fecha de inscripción en Registro Civil)","kind":"textarea","required":true},{"key":"international_adoption_certificate","label":"Resolución/certificado de adopción internacional","kind":"text","required":false}],"display_order":40,"is_active":true},{"id":"and-familia-monoparental","ccaa_code":"ES-AN","title":"Para el padre o madre de familia monoparental y, en su caso, con ascendientes mayores de 75 años","summary":"100 € para padre/madre de familia monoparental, incrementables en 100 € por cada ascendiente >75 años que conviva y dé derecho al mínimo por ascendientes. Suma de bases ≤ 80.000 € (individual) / 100.000 € (conjunta).","legal_reference":"Arts. 13 y 4 y disposición transitoria segunda Ley 5/2021, de 20 de octubre, de Tributos Cedidos de la Comunidad Autónoma de Andalucía","eligibility_rule":{"all_of":[{"op":"eq","path":"ccaa","value":"ES-AN"},{"op":"eq","path":"monoparental","value":true},{"any_of":[{"all_of":[{"op":"eq","path":"declaration_mode","value":"individual"},{"op":"lte","path":"income_base","value":80000}]},{"all_of":[{"op":"eq","path":"declaration_mode","value":"conjunta"},{"op":"lte","path":"income_base","value":100000}]}]}]},"extra_fields":[{"key":"cohabiting_kids_detail","label":"Hijos que conviven (nombre y situación: menor de edad, incapacitado, con curatela…)","kind":"textarea","required":true},{"key":"ascendants_over_75_count","label":"Ascendientes >75 años que conviven y generan mínimo por ascendientes","kind":"number","required":false,"min":0},{"key":"ascendants_detail","label":"Detalle de los ascendientes (nombre y edad)","kind":"textarea","required":false}],"display_order":50,"is_active":true},{"id":"and-familia-numerosa","ccaa_code":"ES-AN","title":"Para familia numerosa","summary":"200 € (categoría general) o 400 € (categoría especial). Suma de bases ≤ 25.000 € (individual) / 30.000 € (conjunta). Requiere ostentar el título de familia numerosa a fecha de devengo. Incompatible con la deducción por nacimiento/adopción/acogimiento.","legal_reference":"Arts. 14 y 5 Ley 5/2021, de 20 de octubre, de Tributos Cedidos de la Comunidad Autónoma de Andalucía","eligibility_rule":{"all_of":[{"op":"eq","path":"ccaa","value":"ES-AN"},{"op":"in","path":"large_family","value":["general","especial"]},{"any_of":[{"all_of":[{"op":"eq","path":"declaration_mode","value":"individual"},{"op":"lte","path":"income_base","value":25000}]},{"all_of":[{"op":"eq","path":"declaration_mode","value":"conjunta"},{"op":"lte","path":"income_base","value":30000}]}]}]},"extra_fields":[{"key":"large_family_category","label":"Categoría de familia numerosa","kind":"select","required":true,"options":[{"value":"general","label":"General"},{"value":"especial","label":"Especial"}]},{"key":"large_family_certificate","label":"Número del título de familia numerosa","kind":"text","required":false},{"key":"title_issuer","label":"Administración que expidió el título","kind":"text","required":false}],"display_order":60,"is_active":true},{"id":"and-gastos-educativos","ccaa_code":"ES-AN","title":"Por gastos educativos","summary":"15% de los gastos satisfechos por enseñanza escolar o extraescolar de idiomas, informática o ambas (en centros docentes, academias o clases particulares con IAE). Límite 150 €/año por cada descendiente con derecho al mínimo. Suma de bases ≤ 80.000 € (individual) / 100.000 € (conjunta).","legal_reference":"Arts. 15 y 60 Ley 5/2021, de 20 de octubre, de Tributos Cedidos de la Comunidad Autónoma de Andalucía","eligibility_rule":{"all_of":[{"op":"eq","path":