o al mínimo por discapacidad. Base imponible ≤ 27.000 € individual / 36.000 € conjunta. Incompatible con ''Por discapacidad del contribuyente'' (misma persona) y con ''Por el cuidado de ascendientes mayores de 75 años'' cuando el ascendiente tenga ≥ 65% (en ese caso se aplica esta).","legal_reference":"Arts. 5 y 13 Ley 8/2013 de la Comunidad Autónoma de Castilla-La Mancha, de Medidas Tributarias","eligibility_rule":{"all_of":[{"op":"eq","path":"ccaa","value":"ES-CM"},{"any_of":[{"all_of":[{"op":"eq","path":"declaration_mode","value":"individual"},{"op":"lte","path":"income_base","value":27000}]},{"all_of":[{"op":"eq","path":"declaration_mode","value":"conjunta"},{"op":"lte","path":"income_base","value":36000}]}]}]},"extra_fields":[{"key":"relatives_with_disability_count","label":"Número de ascendientes/descendientes con discapacidad ≥ 65%","kind":"number","required":true,"min":1},{"key":"relatives_detail","label":"Detalle (relación, nombre, grado de discapacidad)","kind":"textarea","required":true}],"display_order":70,"is_active":true},{"id":"clm-contribuyentes-mayores-75","ccaa_code":"ES-CM","title":"Para contribuyentes mayores de 75 años","summary":"150 € para los contribuyentes mayores de 75 años. No aplica si reside más de 30 días en Centros Residenciales de Mayores subvencionados. Base imponible ≤ 27.000 € individual / 36.000 € conjunta. Incompatible con ''Por discapacidad del contribuyente'' (si el grado es ≥ 65%, se aplica la de discapacidad).","legal_reference":"Arts. 6.1 y 13 Ley 8/2013 de la Comunidad Autónoma de Castilla-La Mancha, de Medidas Tributarias","eligibility_rule":{"all_of":[{"op":"eq","path":"ccaa","value":"ES-CM"},{"op":"age_gte","path":"birth_date","value":75},{"any_of":[{"all_of":[{"op":"eq","path":"declaration_mode","value":"individual"},{"op":"lte","path":"income_base","value":27000}]},{"all_of":[{"op":"eq","path":"declaration_mode","value":"conjunta"},{"op":"lte","path":"income_base","value":36000}]}]}]},"extra_fields":[{"key":"no_residen