caa_code":"ES-CN","title":"Por inversión en vivienda habitual","summary":"Porcentaje variable (5% / 3,5% — o 5,5% / 4% si <40 años) sobre cantidades pagadas para adquisición de vivienda habitual, según base imponible. Base máxima 6.000 € anuales. Aplica en condiciones del art. 68.1 Ley IRPF vigente a 1/1/2012. Límite conjunto 15% de la cuota íntegra autonómica con otras deducciones de vivienda.","legal_reference":"Arts. 14 y 14 quater Texto Refundido Decreto-Legislativo 1/2009 de la Comunidad Autónoma de Canarias","eligibility_rule":{"all_of":[{"op":"eq","path":"ccaa","value":"ES-CN"},{"op":"eq","path":"housing.type","value":"propiedad"},{"op":"eq","path":"housing.is_habitual","value":true},{"op":"lt","path":"income_base","value":46455}]},"extra_fields":[{"key":"amount_paid_eur","label":"Cantidades satisfechas en el ejercicio (€, máx. 6.000)","kind":"number","required":true,"min":0,"max":6000},{"key":"acquisition_date","label":"Fecha de adquisición/construcción de la vivienda habitual","kind":"date","required":true},{"key":"is_under_40","label":"¿Contribuyente menor de 40 años?","kind":"boolean","required":false},{"key":"aids_received_eur","label":"Ayudas públicas exentas que minoran la base (€)","kind":"number","required":false,"min":0}],"display_order":160,"is_active":true},{"id":"can-obras-rehabilitacion-energetica","ccaa_code":"ES-CN","title":"Por obras de rehabilitación energética de la vivienda habitual","summary":"12% de cantidades satisfechas (mediante medios bancarios) por obras de rehabilitación energética de la vivienda habitual. Base máxima 7.000 € anuales. Límite 10% de la cuota íntegra autonómica (15% conjunto con otras deducciones de vivienda). Requiere certificados de eficiencia energética.","legal_reference":"Arts. 14 bis y 14 quater Texto Refundido Decreto-Legislativo 1/2009 de la Comunidad Autónoma de Canarias","eligibility_rule":{"all_of":[{"op":"eq","path":"ccaa","value":"ES-CN"},{"op":"eq","path":"housing.type","value":"propiedad"},{"op":"eq","path":"housing.is_habitual","value":true}]},"extra_fields":[{"key":"energy_works_amount_eur","label":"Cantidades satisfechas (€, máx. 7.000)","kind":"number","required":true,"min":0,"max":7000},{"key":"works_description","label":"Descripción de las obras de rehabilitación energética","kind":"textarea","required":true},{"key":"bank_payment","label":"Confirmo el pago por tarjeta, transferencia, cheque nominativo o ingreso en cuenta","kind":"boolean","required":true},{"key":"energy_certificate_before","label":"Certificado de eficiencia energética previo a las obras","kind":"text","required":false},{"key":"energy_certificate_after","label":"Certificado de eficiencia energética posterior a las obras","kind":"text","required":false},{"key":"aids_received_eur","label":"Ayudas públicas exentas recibidas (€)","kind":"number","required":false,"min":0}],"display_order":170,"is_active":true},{"id":"can-adecuacion-vivienda-discapacidad","ccaa_code":"ES-CN","title":"Por obras de adecuación de la vivienda habitual por personas con discapacidad","summary":"14% (18% si ≥ 65 años) de cantidades satisfechas en obras de adecuación de la vivienda habitual cuando el contribuyente tenga discapacidad ≥ 65%. También aplicable si la discapacidad la padece cónyuge, ascendientes o descendientes que convivan, sin rentas anuales > 35.735 €. Base máxima 15.000 € por contribuyente.","legal_reference":"Arts. 14 ter y 14 quater Texto Refundido Decreto-Legislativo 1/2009 de la Comunidad Autónoma de Canarias","eligibility_rule":{"all_of":[{"op":"eq","path":"ccaa","value":"ES-CN"},{"op":"eq","path":"housing.is_habitual","value":true}]},"extra_fields":[{"key":"adaptation_amount_eur","label":"Cantidades satisfechas en obras de adecuación (€, máx. 15.000)","kind":"number","required":true,"min":0,"max":15000},{"key":"disabled_person","label":"Persona con discapacidad ≥ 65%","kind":"select","required":true,"options":[{"value":"contribuyente","label":"El propio contribuyente"},{"value":"conyuge","label":"Cónyuge"},{"value":"ascendiente","label":"Ascendiente conviviente"},{"value":"descendiente","label":"Descendiente conviviente"}]},{"key":"disabled_person_over_65","label":"¿La persona con discapacidad es mayor de 65 años?","kind":"boolean","required":false},{"key":"works_certificate","label":"Resolución/certificado de la consejería de discapacidad acreditando necesidad","kind":"text","required":false}],"display_order":180,"is_active":true},{"id":"can-alquiler-vivienda-habitual","ccaa_code":"ES-CN","title":"Por alquiler de vivienda habitual","summary":"24% de cantidades pagadas por alquiler de vivienda habitual, máximo 740 €/año (760 € si <40 años o ≥75 años). El alquiler debe superar el 10% de la base imponible. Base imponible ≤ 46.455 € (indiv.) / 61.770 € (conj.).","legal_reference":"Art. 15 Texto Refundido Decreto-Legislativo 1/2009 de la Comunidad Autónoma de Canarias","eligibility_rule":{"all_of":[{"op":"eq","path":"ccaa","value":"ES-CN"},{"op":"eq","path":"housing.type","value":"alquiler"},{"any_of":[{"all_of":[{"op":"eq","path":"declaration_mode","value":"individual"},{"op":"lte","path":"income_base","value":46455}]},{"all_of":[{"op":"eq","path":"declaration_mode","value":"conjunta"},{"op":"lte","path":"income_base","value":61770}]}]}]},"extra_fields":[{"key":"annual_rent_eur","label":"Renta anual pagada (€)","kind":"number","required":true,"min":0},{"key":"landlord_nif","label":"NIF del arrendador","kind":"text","required":true},{"key":"property_reference","label":"Referencia catastral de la vivienda","kind":"text","required":true},{"key":"tenant_age_bracket","label":"Tramo de edad","kind":"select","required":false,"options":[{"value":"menor_40","label":"Menor de 40 años"},{"value":"40_a_74","label":"Entre 40 y 74 años"},{"value":"75_o_mas","label":"75 años o más"}]}],"display_order":190,"is_active":true},{"id":"can-arrendamiento-dacion-pago","ccaa_code":"ES-CN","title":"Por arrendamiento de vivienda habitual vinculado a determinadas operaciones de dación en pago","summary":"25% de cantidades pagadas por el alquiler de la vivienda habitual, máximo 1.200 €/año, cuando el contribuyente transmitió previamente esa vivienda a la entidad financiera acreedora en dación en pago y continúa ocupándola en alquiler con opción de compra. Base imponible ≤ 46.455 € (indiv.) / 61.770 € (conj.).","legal_reference":"Art. 15 bis Texto Refundido Decreto-Legislativo 1/2009 de la Comunidad Autónoma de Canarias","eligibility_rule":{"all_of":[{"op":"eq","path":"ccaa","value":"ES-CN"},{"op":"eq","path":"housing.type","value":"alquiler"},{"any_of":[{"all_of":[{"op":"eq","path":"declaration_mode","value":"individual"},{"op":"lte","path":"income_base","value":46455}]},{"all_of":[{"op":"eq","path":"declaration_mode","value":"conjunta"},{"op":"lte","path":"income_base","value":61770}]}]}]},"extra_fields":[{"key":"annual_rent_eur","label":"Renta anual pagada (€, máx. base 1.200)","kind":"number","required":true,"min":0},{"key":"lender_entity","label":"Entidad financiera acreedora (o filial inmobiliaria del grupo)","kind":"text","required":true},{"key":"transfer_date","label":"Fecha de la dación en pago","kind":"date","required":true},{"key":"property_reference","label":"Referencia catastral de la vivienda","kind":"text","required":false}],"display_order":200,"is_active":true},{"id":"can-gastos-adecuacion-arrendamiento","ccaa_code":"ES-CN","title":"Por gastos derivados de la adecuación de un inmueble con destino al arrendamiento como vivienda habitual","summary":"10% de gastos de reparación, formalización del contrato, primas de seguros (daños e impagos) y certificados de eficiencia energética, en inmuebles destinados al arrendamiento como vivienda habitual. Límite 150 € por inmueble (deducción del arrendador).","legal_reference":"Art. 15 ter Texto Refundido Decreto-Legislativo 1/2009 de la Comunidad Autónoma de Canarias","eligibility_rule":{"all_of":[{"op":"eq","path":"ccaa","value":"ES-CN"}]},"extra_fields":[{"key":"deductible_expenses_eur","label":"Gastos justificados con factura (€)","kind":"number","required":true,"min":0},{"key":"expense_types","label":"Tipos de gasto (reparación, contrato, seguros, certificado energético)","kind":"textarea","required":false},{"key":"rented_property_count","label":"Inmuebles arrendados","kind":"number","required":false,"min":1},{"key":"provider_nif","label":"NIF del prestador del servicio (obligatorio si reparación/conservación)","kind":"text","required":false}],"display_order":210,"is_active":true},{"id":"can-primas-seguros-impago-alquiler","ccaa_code":"ES-CN","title":"Por gastos en primas de seguros de crédito para cubrir impagos de rentas de arrendamientos de vivienda (deducción del arrendador)","summary":"75% de las primas de seguros de crédito para cubrir impagos de rentas de arrendamiento de inmueble situado en Canarias destinado a vivienda. Máximo 150 €/año. Requiere contrato ≥ 1 año, depósito de fianza, declaración del rendimiento y renta mensual ≤ 800 €.","legal_reference":"Art. 15 quater Texto Refundido Decreto-Legislativo 1/2009 de la Comunidad Autónoma de Canarias","eligibility_rule":{"all_of":[{"op":"eq","path":"ccaa","value":"ES-CN"}]},"extra_fields":[{"key":"insurance_premium_eur","label":"Primas de seguro pagadas en el año (€)","kind":"number","required":true,"min":0},{"key":"tenant_nif","label":"NIF del arrendatario","kind":"text","required":true},{"key":"property_reference","label":"Referencia catastral del inmueble arrendado","kind":"text","required":true},{"key":"monthly_rent_eur","label":"Renta mensual del arrendamiento (€, máx. 800)","kind":"number","required":true,"min":0,"max":800},{"key":"deposit_filed","label":"Confirmo que se constituyó el depósito de la fianza ante el órgano competente","kind":"boolean","required":true}],"display_order":220,"is_active":true},{"id":"can-puesta-mercado-arrendamiento","ccaa_code":"ES-CN","title":"Por la puesta de viviendas en el mercado de arrendamiento de viviendas habituales","summary":"1.000 € por cada inmueble si