876,"max":22000},{"key":"other_income_eur","label":"Suma del resto de bases (general + ahorro, excluyendo trabajo) (€, máx. 1.600)","kind":"number","required":false,"min":0,"max":1600}],"display_order":240,"is_active":true},{"id":"can-gasto-enfermedad","ccaa_code":"ES-CN","title":"Por gasto de enfermedad (general)","summary":"12% de honorarios pagados a profesionales médicos/sanitarios (no farmacéuticos) por prevención, diagnóstico o tratamiento, salud dental, embarazo, accidentes e invalidez; y 12% en gafas/lentillas y aparatos para suplir deficiencias físicas. Límite 500 € indiv. / 700 € conj. (+100 € si ≥65 años o discapacidad ≥65%) cuando base ≤ 46.455 € (indiv.) / 61.770 € (conj.); 150 € por contribuyente en otro caso.","legal_reference":"Art. 16 ter Texto Refundido Decreto-Legislativo 1/2009 de la Comunidad Autónoma de Canarias","eligibility_rule":{"all_of":[{"op":"eq","path":"ccaa","value":"ES-CN"}]},"extra_fields":[{"key":"medical_expenses_eur","label":"Gastos en profesionales médicos/sanitarios (€)","kind":"number","required":false,"min":0},{"key":"devices_expenses_eur","label":"Gastos en aparatos / gafas / lentillas (€)","kind":"number","required":false,"min":0},{"key":"provider_nifs","label":"NIF de los prestadores de servicios médicos","kind":"textarea","required":false},{"key":"is_over_65_or_disabled_65","label":"¿Contribuyente ≥ 65 años o con discapacidad ≥ 65%?","kind":"boolean","required":false}],"display_order":250,"is_active":true},{"id":"can-familiares-dependientes-discapacidad","ccaa_code":"ES-CN","title":"Por familiares dependientes con discapacidad","summary":"a) 600 € por cada ascendiente o descendiente con discapacidad ≥ 65% que genere mínimo por discapacidad. b) 20% de las cuotas a la Seguridad Social pagadas por un empleado de hogar destinado a la asistencia, cuando el familiar con discapacidad ≥ 65% necesite tercera persona. Límite 500 €/año. Base imponible ≤ 46.455 € (indiv.) / 61.770 € (conj.).","legal_reference":"Art. 16 quater Texto Refundido Decreto-Legislativo 1/2009 de la Comunidad Autónoma de Canarias","eligibility_rule":{"all_of":[{"op":"eq","path":"ccaa","value":"ES-CN"},{"any_of":[{"all_of":[{"op":"eq","path":"declaration_mode","value":"individual"},{"op":"lte","path":"income_base","value":46455}]},{"all_of":[{"op":"eq","path":"declaration_mode","value":"conjunta"},{"op":"lte","path":"income_base","value":61770}]}]}]},"extra_fields":[{"key":"dependents_count","label":"Número de ascendientes/descendientes con discapacidad ≥ 65% y mínimo por discapacidad","kind":"number","required":false,"min":0},{"key":"dependents_detail","label":"Detalle de los familiares (nombre, parentesco, grado de discapacidad)","kind":"textarea","required":false},{"key":"household_employee_ss_eur","label":"Cuotas Seguridad Social Empleados Hogar pagadas (€, supuesto b)","kind":"number","required":false,"min":0},{"key":"household_employee_nif","label":"NIF / NIE del empleado de hogar","kind":"text","required":false}],"display_order":260,"is_active":true},{"id":"can-empleados-hogar","ccaa_code":"ES-CN","title":"Por cuotas satisfechas a la Seguridad Social por la contratación de empleados o empleadas de hogar","summary":"20% de las cuotas a la Seguridad Social pagadas por un empleado del hogar familiar (Sistema Especial Empleados de Hogar) destinado a la vivienda habitual. Máximo 500 € anuales. Aplica si: hay mínimo por descendientes y rendimientos de trabajo/actividades, o si el contribuyente tiene ≥ 75 años, o si tiene > 65 años con discapacidad.","legal_reference":"Art. 16 quinquies Texto Refundido Decreto-Legislativo 1/2009 de la Comunidad Autónoma de Canarias","eligibility_rule":{"all_of":[{"op":"eq","path":"ccaa","value":"ES-CN"},{"any_of":[{"op":"gte","path":"kids.length","value":1},{"op":"age_gte","path":"birth_date","value":75},{"all_of":[{"op":"age_gte","path":"birth_date","value":66},{"op":"gte","path":"disability_pct","value":33}]}]}]},"extra_fields":[{"key":"social_security_contributions_eur","label":"Cuotas Seguridad Social Empleados de Hogar pagadas (€)","kind":"number","required":true,"min":0},{"key":"circumstance","label":"Circunstancia que da derecho","kind":"select","required":true,"options":[{"value":"minimo_descendientes","label":"Mínimo por descendientes + rendimientos del trabajo/actividades económicas"},{"value":"mayor_75","label":"Contribuyente ≥ 75 años"},{"value":"mayor_65_discapacidad","label":"Contribuyente > 65 años con discapacidad (≥ 65% física/orgánica/sensorial o ≥ 33% cognitiva/psicosocial)"}]},{"key":"household_employee_nif","label":"NIF / NIE del empleado de hogar","kind":"text","required":true}],"display_order":270,"is_active":true},{"id":"cat-nacimiento-adopcion-acogimiento","ccaa_code":"ES-CT","title":"Por nacimiento o adopción de un hijo o de una hija o por acogimiento familiar","summary":"150 € en declaración individual de cada progenitor; 300 € en declaración conjunta o si es familia monoparental. El acogimiento debe haberse acordado conforme a la Ley 14/2010. La deducción por adopción es incompatible con la de acogimiento familiar por el mismo hijo.","legal_reference":"Art. 612-1 Decreto Legislativo 1/2024 de Cataluña","eligibility_rule":{"all_of":[{"op":"eq","path":"ccaa","value":"ES-CT"},{"op":"gte","path":"kids.length","value":1}]},"extra_fields":[{"key":"event_type","label":"Hecho que genera la deducción","kind":"select","required":true,"options":[{"value":"nacimiento","label":"Nacimiento"},{"value":"adopcion","label":"Adopción"},{"value":"acogimiento","label":"Acogimiento familiar (simple o permanente)"}]},{"key":"kids_born_or_adopted","label":"Hijos/as nacidos, adoptados o acogidos en el ejercicio (nombre y fecha)","kind":"textarea","required":true},{"key":"is_monoparental","label":"¿Familia monoparental?","kind":"boolean","required":false},{"key":"joint_declaration","label":"¿Declaración conjunta?","kind":"boolean","required":false}],"display_order":10,"is_active":true},{"id":"cat-contribuyentes-viudos","ccaa_code":"ES-CT","title":"Para contribuyentes que hayan quedado viudos en los ejercicios 2023, 2024 y 2025","summary":"150 € con carácter general; 300 € si la persona viuda tiene a su cargo uno o más descendientes que generen derecho al mínimo por descendientes. Aplica en el ejercicio de la viudedad y los dos siguientes.","legal_reference":"Art. 612-2 Decreto Legislativo 1/2024 de Cataluña","eligibility_rule":{"all_of":[{"op":"eq","path":"ccaa","value":"ES-CT"},{"op":"eq","path":"civil_status","value":"viudo"}]},"extra_fields":[{"key":"widowhood_year","label":"Año en que quedó viudo/a (2023, 2024 o 2025)","kind":"select","required":true,"options":[{"value":"2023","label":"2023"},{"value":"2024","label":"2024"},{"value":"2025","label":"2025"}]},{"key":"has_dependent_descendants","label":"¿Tiene descendientes a cargo con derecho al mínimo por descendientes?","kind":"boolean","required":true}],"display_order":20,"is_active":true},{"id":"cat-alquiler-vivienda-habitual","ccaa_code":"ES-CT","title":"Por alquiler de la vivienda habitual","summary":"10% de las cantidades pagadas (límite 500 €/año, 1.000 € en conjunta o si pertenece a familia numerosa/monoparental). Requiere: <35 años, parado >183 días, discapacidad ≥65% o viudo ≥65 años. Base imponible ≤ 30.000 € (individual) o 45.000 € (conjunta).","legal_reference":"Art. 612-3 Decreto Legislativo 1/2024 de Cataluña","eligibility_rule":{"all_of":[{"op":"eq","path":"ccaa","value":"ES-CT"},{"op":"eq","path":"housing.type","value":"alquiler"},{"any_of":[{"all_of":[{"op":"eq","path":"declaration_mode","value":"individual"},{"op":"lte","path":"income_base","value":30000}]},{"all_of":[{"op":"eq","path":"declaration_mode","value":"conjunta"},{"op":"lte","path":"income_base","value":45000}]}]},{"any_of":[{"op":"age_lt","path":"birth_date","value":35},{"op":"gte","path":"disability_pct","value":65},{"op":"in","path":"large_family","value":["general","especial"]},{"op":"eq","path":"monoparental","value":true},{"all_of":[{"op":"eq","path":"civil_status","value":"viudo"},{"op":"age_gte","path":"birth_date","value":65}]}]}]},"extra_fields":[{"key":"annual_rent_eur","label":"Renta anual pagada (€)","kind":"number","required":true,"min":0},{"key":"landlord_nif","label":"NIF del arrendador/a","kind":"text","required":true},{"key":"qualifying_circumstance","label":"Circunstancia que da derecho","kind":"select","required":true,"options":[{"value":"menor_35","label":"Tener 35 años o menos a la fecha de devengo"},{"value":"paro_183","label":"Haber estado en paro 183 días o más durante el ejercicio"},{"value":"discapacidad_65","label":"Grado de discapacidad ≥ 65%"},{"value":"viudo_65","label":"Viudo/a con 65 años o más"},{"value":"familia_numerosa","label":"Familia numerosa"},{"value":"monoparental","label":"Familia monoparental"}]},{"key":"is_large_or_monoparental","label":"¿Familia numerosa o monoparental? (eleva el límite a 1.000 €)","kind":"boolean","required":false}],"display_order":30,"is_active":true},{"id":"cat-rehabilitacion-vivienda-habitual","ccaa_code":"ES-CT","title":"Por rehabilitación de la vivienda habitual","summary":"1,5% de las cantidades satisfechas por la rehabilitación de la vivienda que constituya o vaya a constituir la vivienda habitual del contribuyente. Base máxima 9.040 €/año.","legal_reference":"Art. 612-4 Decreto Legislativo 1/2024 de Cataluña","eligibility_rule":{"all_of":[{"op":"eq","path":"ccaa","value":"ES-CT"},{"op":"eq","path":"housing.type","value":"propiedad"},{"op":"eq","path":"housing.is_habitual","value":true}]},"extra_fields":[{"key":"rehabilitation_amount_eur","label":"Cantidades satisfechas por rehabilitación (€)","kind":"number","required":true,"min":0},{"key":"property_reference","label":"Referencia catastral del inmueble","kind":"text","required":false},{"key":"works_description","label":"Descripción de las obras de rehabilitación","kind":"textarea","required":false}],"display_order":40,"is_active":true},{"id":"cat-intereses-prestamos-master-doctorado","ccaa_code":"ES-CT","title":"Por el pago de intereses de préstamos para los estudios de máster y doctorado","summary":"Importe de los intereses pagados en el ejercicio que correspondan a préstamos concedidos a través de la Agencia de Gestión de Ayudas Universitarias y de Investigación (AGAUR) para financiar estudios de máster y doctorado.","legal_reference":"Art. 612-5 Decreto Legislativo 1/2024 de Cataluña","eligibility_rule":{"all_of":[{"op":"eq","path":"ccaa","value":"ES-CT"}]},"extra_fields":[{"key":"interest_paid_eur","label":"Intereses satisfechos en el ejercicio (€)","kind":"number","required":true,"min":0},{"key":"loan_identifier","label":"Número de identificación del préstamo (casilla [1928] Anexo B.5)","kind":"text","required":true},{"key":"study_level","label":"Nivel de estudios financiado","kind":"select","required":true,"options":[{"value":"master","label":"Máster"},{"value":"doctorado","label":"Doctorado"}]}],"display_order":50,"is_active":true},{"id":"cat-donativos-lengua-catalana-occitana","ccaa_code":"ES-CT","title":"Por donativos a entidades que fomentan el uso de la lengua catalana o de la occitana","summary":"15% de las cantidades donadas a favor del Institut d''Estudis Catalans, Institut d''Estudis Aranesos u otras entidades privadas sin ánimo de lucro que fomenten la lengua catalana u occitana. Límite del 10% de la cuota íntegra autonómica.","legal_reference":"Art. 612-6 Decreto Legislativo 1/2024 de Cataluña","eligibility_rule":{"all_of":[{"op":"eq","path":"ccaa","value":"ES-CT"}]},"extra_fields":[{"key":"donation_amount_eur","label":"Importe total donado (€)","kind":"number","required":true,"min":0},{"key":"donation_recipients","label":"Entidades receptoras y NIF","kind":"textarea","required":true}],"display_order":60,"is_active":true},{"id":"cat-donativos-investigacion-i-d-i","ccaa_code":"ES-CT","title":"Por donativos a entidades que fomentan la investigación científica y el desarrollo y la innovación tecnológicos","summary":"30% de las cantidades donadas a universidades 