to","ccaa_code":"ES-VC","title":"Por residir habitualmente en un municipio en riesgo de despoblamiento","summary":"330 € por residencia habitual en municipio beneficiario del Fondo de Cooperación Municipal contra el despoblamiento de la Comunitat Valenciana. Incremento de 132 €, 198 € o 264 € si el contribuyente tiene derecho al mínimo por 1, 2 o 3+ descendientes.","legal_reference":"Art. 4.Uno.aa) Ley 13/1997, de la Comunitat Valenciana","eligibility_rule":{"all_of":[{"op":"eq","path":"ccaa","value":"ES-VC"},{"op":"eq","path":"small_municipality","value":true}]},"extra_fields":[{"key":"municipality","label":"Municipio de residencia habitual (beneficiario del Fondo)","kind":"text","required":true},{"key":"descendants_count","label":"Número de descendientes con derecho al mínimo","kind":"number","required":false,"min":0}],"display_order":300,"is_active":true},{"id":"val-tratamientos-fertilidad","ccaa_code":"ES-VC","title":"Por cantidades satisfechas en tratamientos de fertilidad realizados en clínicas o centros autorizados","summary":"100 € por tratamientos de fertilidad realizados en clínicas o centros autorizados. La contribuyente debe ser mujer con edad entre 40 y 45 años. Bases máximas: 30.000 €/47.000 €.","legal_reference":"Art. 4.Uno.ab) Ley 13/1997, de la Comunitat Valenciana","eligibility_rule":{"all_of":[{"op":"eq","path":"ccaa","value":"ES-VC"},{"op":"age_gte","path":"birth_date","value":40},{"op":"age_lt","path":"birth_date","value":46},{"any_of":[{"all_of":[{"op":"eq","path":"declaration_mode","value":"individual"},{"op":"lte","path":"income_base","value":30000}]},{"all_of":[{"op":"eq","path":"declaration_mode","value":"conjunta"},{"op":"lte","path":"income_base","value":47000}]}]}]},"extra_fields":[{"key":"treatment_amount_eur","label":"Cantidades satisfechas por tratamientos de fertilidad (€)","kind":"number","required":true,"min":0},{"key":"clinic_name","label":"Clínica o centro autorizado","kind":"text","required":true}],"display_order":310,"is_active":true},{"id":"val-gastos-salud","ccaa_code":"ES-VC","title":"Por cantidades satisfechas en determinados gastos de salud","summary":"Hasta 100 € (150 € en familias numerosas/monoparentales) por gastos de tratamiento de enfermedades crónicas de alta complejidad o raras, y de daño cerebral adquirido / alzhéimer. 30% por gastos de salud bucodental no estética (límite 150 €), salud mental (límite 150 €) o lentes graduadas (límite 100 €). Bases máximas: 60.000 €/78.000 €.","legal_reference":"Art. 4.Uno.ac) Ley 13/1997, de la Comunitat Valenciana","eligibility_rule":{"all_of":[{"op":"eq","path":"ccaa","value":"ES-VC"},{"any_of":[{"all_of":[{"op":"eq","path":"declaration_mode","value":"individual"},{"op":"lte","path":"income_base","value":60000}]},{"all_of":[{"op":"eq","path":"declaration_mode","value":"conjunta"},{"op":"lte","path":"income_base","value":78000}]}]}]},"extra_fields":[{"key":"expense_category","label":"Categoría de gasto","kind":"select","required":true,"options":[{"value":"cronicas_raras","label":"Enfermedades crónicas de alta complejidad o raras"},{"value":"dano_cerebral_alzheimer","label":"Daño cerebral adquirido o alzhéimer"},{"value":"bucodental","label":"Salud bucodental no estética"},{"value":"salud_mental","label":"Salud mental"},{"value":"lentes_graduadas","label":"Lentes graduadas / lentes de contacto"}]},{"key":"expense_amount_eur","label":"Importe satisfecho (€)","kind":"number","required":true,"min":0},{"key":"provider_nif","label":"NIF del profesional/centro sanitario","kind":"text","required":true},{"key":"is_large_or_mono_family","label":"¿Familia numerosa o monoparental? (para gastos enfermedades crónicas)","kind":"boolean","required":false}],"display_order":320,"is_active":true},{"id":"val-deporte-actividades-saludables","ccaa_code":"ES-VC","title":"Por cantidades satisfechas en gastos asociados a la práctica del deporte y actividades saludables","summary":"30% de los gastos por cuotas de gimnasios/clubes/federaciones, equipamiento deportivo federado, servicios de entrenamiento, traumatología, dietética, fisioterapia o podología. 50% si el declarante > 65 años o discapacidad ≥ 33%. 100% si > 75 años o discapacidad ≥ 65%. Límite 150 €/año/contribuyente. Bases máximas: 60.000 €/78.000 €.","legal_reference":"Art. 4.Uno.ad) Ley 13/1997, de la Comunitat Valenciana","eligibility_rule":{"all_of":[{"op":"eq","path":"ccaa","value":"ES-VC"},{"any_of":[{"all_of":[{"op":"eq","path":"declaration_mode","value":"individual"},{"op":"lte","path":"income_base","value":60000}]},{"all_of":[{"op":"eq","path":"declaration_mode","value":"conjunta"},{"op":"lte","path":"income_base","value":78000}]}]}]},"extra_fields":[{"key":"sport_expenses_eur","label":"Gastos satisfechos en deporte / actividades saludables (€)","kind":"number","required":true,"min":0},{"key":"expense_breakdown","label":"Detalle de gastos (cuotas, equipamiento federado, entrenadores, fisio, etc.)","kind":"textarea","required":true},{"key":"qualifying_circumstance","label":"Circunstancia personal","kind":"select","required":false,"options":[{"value":"ninguna","label":"Ninguna"},{"value":"mayor_65_o_disc_33","label":"> 65 años o discapacidad ≥ 33%"},{"value":"mayor_75_o_disc_65","label":"> 75 años o discapacidad ≥ 65%"}]}],"display_order":330,"is_active":true},{"id":"val-fomento-formacion-musical","ccaa_code":"ES-VC","title":"Por cantidades satisfechas en gastos vinculados con el fomento y formación musicales","summary":"100% de las cantidades satisfechas por tasas y cuotas de conservatorios y escuelas de música inscritos, cuotas como socios de sociedades musicales federadas, formación musical en centros oficiales, instrumentos y partituras adquiridos en el marco de estas actividades, y entradas para conciertos de las entidades anteriores. Límite 150 €/año/contribuyente. Bases máximas: 60.000 €/78.000 €.","legal_reference":"Art. 4.Uno.ae) Ley 13/1997, de la Comunitat Valenciana","eligibility_rule":{"all_of":[{"op":"eq","path":"ccaa","value":"ES-VC"},{"any_of":[{"all_of":[{"op":"eq","path":"declaration_mode","value":"individual"},{"op":"lte","path":"income_base","value":60000}]},{"all_of":[{"op":"eq","path":"declaration_mode","value":"conjunta"},{"op":"lte","path":"income_base","value":78000}]}]}]},"extra_fields":[{"key":"music_expenses_eur","label":"Gastos satisfechos en formación / fomento musical (€)","kind":"number","required":true,"min":0},{"key":"music_entity","label":"Centros o entidades (conservatorio, escuela, sociedad musical, etc.)","kind":"textarea","required":true}],"display_order":340,"is_active":true},{"id":"val-dana-vivienda-habitual","ccaa_code":"ES-VC","title":"Por destinar cantidades a paliar los daños materiales sobre la vivienda habitual derivados de la DANA de octubre de 2024","summary":"100% de los gastos de reparación acometidos por daños causados por el temporal DANA de octubre de 2024 en viviendas habituales situadas en municipios incluidos en el Anexo del Acuerdo del Consell 4-11-2024 (no cubiertos por seguros). Límite máximo 2.000 €. Bases máximas: 45.000 €/60.000 €. Aplicable exclusivamente en ejercicios 2024 y 2025.","legal_reference":"Art. 4 Decreto Ley 12/2024 de la Comunitat Valenciana","eligibility_rule":{"all_of":[{"op":"eq","path":"ccaa","value":"ES-VC"},{"op":"eq","path":"housing.is_habitual","value":true},{"any_of":[{"all_of":[{"op":"eq","path":"declaration_mode","value":"individual"},{"op":"lte","path":"income_base","value":45000}]},{"all_of":[{"op":"eq","path":"declaration_mode","value":"conjunta"},{"op":"lte","path":"income_base","value":60000}]}]}]},"extra_fields":[{"key":"repair_expenses_eur","label":"Gastos de reparación satisfechos (no cubiertos por seguro) (€)","kind":"number","required":true,"min":0},{"key":"municipality","label":"Municipio (incluido en el Anexo DANA 2024)","kind":"text","required":true},{"key":"public_aid_received_eur","label":"Ayudas públicas recibidas para los mismos gastos (a descontar) (€)","kind":"number","required":false,"min":0}],"display_order":350,"is_active":true},{"id":"val-dana-fondos-propios-entidades","ccaa_code":"ES-VC","title":"Por aportaciones a los fondos propios de entidades que desarrollen actividades económicas (DANA 2024)","summary":"45% de las cantidades invertidas en la suscripción/desembolso de acciones o participaciones de SA/SL/SAL u aportaciones a cooperativas con domicilio social en el ámbito territorial de la DANA, que hayan solicitado ERTE como consecuencia del temporal. Límite máximo 9.900 € por contribuyente. Base máxima 30% de la base liquidable. Aplicable a inversiones efectuadas entre el 13-nov-2024 y el 31-dic-2025.","legal_reference":"Art. 5 Decreto Ley 12/2024 de la Comunitat Valenciana","eligibility_rule":{"all_of":[{"op":"eq","path":"ccaa","value":"ES-VC"}]},"extra_fields":[{"key":"investment_amount_eur","label":"Importe invertido en el ejercicio (€)","kind":"number","required":true,"min":0},{"key":"entity_nif","label":"NIF de la entidad participada (domicilio en ámbito DANA)","kind":"text","required":true},{"key":"investment_date","label":"Fecha de la inversión / escritura (entre 13-11-2024 y 31-12-2025)","kind":"date","required":true},{"key":"erte_filed","label":"Confirmo que la entidad solicitó ERTE como consecuencia del temporal","kind":"boolean","required":true}],"display_order":360,"is_active":true}]'::jsonb) AS row;
